        { id: "lead1-l2", title: "Risk-based testing", duration: "40 min", content: "<p>Priorize por impacto × probabilidade. Matriz de risco guia onde investir automação e testes exploratórios.</p>", resources: [] },
        { id: "lead1-l3", title: "Quality metrics que importam", duration: "35 min", content: "<p>Escape rate, MTTR de bugs, flakiness %, coverage útil (não vanity metrics). Dashboards para decisão, não punição.</p>", resources: [] }
